void draw_bitmap_char(const unsigned char bitmap[7], int x, int y, short int color) {
    for (int row = 0; row < 7; row++)
        for (int col = 0; col < 5; col++)
            if (bitmap[row] & (1 << (4 - col)))
                draw_rect(x + col * SCALE, y + row * SCALE, SCALE, SCALE, color);
}


