void draw_string(const char *str, int x, int y, short int color) {
    int letter_w = 5 * SCALE + GAP;
    for (int i = 0; str[i] != '\0'; i++) {
        char c = str[i];
        if (c >= 'A' && c <= 'Z')
            draw_letter(font_table[c - 'A'], x + i * letter_w, y, color);
        else if (c == '0')
            draw_bitmap_char(font_0, x + i * letter_w, y, color);
        else if (c == '3')
            draw_bitmap_char(font_3, x + i * letter_w, y, color);
        else if (c == ':')
            draw_bitmap_char(font_colon, x + i * letter_w, y, color);
        else if (c == '[')
            draw_bitmap_char(font_lbracket, x + i * letter_w, y, color);
        else if (c == ']')
            draw_bitmap_char(font_rbracket, x + i * letter_w, y, color);
        // space: no drawing, just skips (index still advances = blank gap)
    }
}



