volatile char *character_buffer = (char *)CHAR_BUF_BASE;

void write_char(int x, int y, char c) {
    *(character_buffer + (y << 7) + x) = c;
}

void write_text(int x, int y, const char *text) {
    while (*text) {
        write_char(x, y, *text);
        x++;
        text++;
    }
}

void clear_text() {
    for (int y = 0; y < 60; y++) {
        for (int x = 0; x < 80; x++) {
            write_char(x, y, ' ');
        }
    }
}

void plot_pixel(int x, int y, short int color) {
    volatile short int *pixel_address;
    // Standard DE1-SoC address calculation
    pixel_address = (short int *)(pixel_buffer_start + (y << 10) + (x << 1));
    *pixel_address = color;
}

void clear_screen() {
    for (int y = 0; y < 240; y++) {
        for (int x = 0; x < 320; x++) {
            plot_pixel(x, y, 0x0000);
        }
    }
}

void draw_image() {
    int index = 0;
    for (int y = 0; y < HEIGHT; y++) {
        for (int x = 0; x < WIDTH; x++) {
            unsigned short color = akinator_map[index];
            plot_pixel(x, y, color);
            index++;
        }
    }
}

int main(void) {
    // Initialize the pixel buffer address from the FPGA register
    pixel_buffer_start = *pixel_ctrl_ptr;
    
    clear_screen();
    draw_image();
	draw_string("PRESS ANY", 10, 100, 0xFFFF);
	draw_string("KEY[3:0]", 10, 120, 0xFFFF);
	draw_string("TO START", 10, 140, 0xFFFF);

    clear_text(); 
    
    while (1);
}